/**
 * Calculate the factorial of $n$.
 * @param n the input number
 * @return the factorial
 */
public static long factorial(int n) {
    if (n < 0) {
        throw new IllegalArgumentException("Input must be a non-negative integer.");
    }
    long result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

