private OuterFaceCirculator selectOnOuterFace(Predicate<Node> predicate, Node start, Node stop, int dir) {
    OuterFaceCirculator circulator = new OuterFaceCirculator();
    Node currentNode = start;
    // Assuming we have a way to get the next node in the specified direction
    while (!currentNode.equals(stop)) {
        if (predicate.test(currentNode)) {
            // Return circulator to the node satisfying the predicate
            return circulator;
        }
        // Method to get the next node
        currentNode = getNextNode(currentNode, dir);
    }
    // Return circulator to the stop node if no node satisfies the predicate
    return circulator;
}

