                    unescaped.append('\t');
                    break;
                case 'r':
                    unescaped.append('\r');
                    break;
                case 'f':
                    unescaped.append('\f');
                    break;
                case 'b':
                    unescaped.append('\b');
                    break;
                case '"':
                    unescaped.append('"');
                    break;
                case '\'':
                    unescaped.append('\'');
                    break;
                case '\\':
                    unescaped.append('\\');
                    break;
                default:
                    unescaped.append(currentChar);
                    break;
            }
            isEscaped = false;
        } else {
            if (currentChar == '\\') {
                isEscaped = true;
            } else {
                unescaped.append(currentChar);
            }
        }
    }
